// Filter posts whose scheduled date+time has passed (CST / UTC-6)
const items = $input.all();
if (!items || items.length === 0) return [];

const now = new Date();
const cstMs = now.getTime() + (now.getTimezoneOffset() - 360) * 60000;
const cstNow = new Date(cstMs);
const nowDate = cstNow.toISOString().split('T')[0];
const nowTime = String(cstNow.getHours()).padStart(2,'0') + ':' + String(cstNow.getMinutes()).padStart(2,'0');

return items.filter(item => {
  const d = item.json.scheduled_date;
  const t = (item.json.scheduled_time || '').substring(0, 5);
  if (!d || !t) return false;
  return d < nowDate || (d === nowDate && t <= nowTime);
});

// ═══ FACEBOOK PUBLISHER ═══
// Posts images and videos to a Facebook Page via Graph API v21.
//
// Setup:
//   1. Create Meta App at developers.facebook.com
//   2. Add Pages API product
//   3. Generate long-lived Page Access Token
//   4. Paste credentials below

const FB_TOKEN = 'YOUR_META_PAGE_ACCESS_TOKEN';
const FB_PAGE  = 'YOUR_FACEBOOK_PAGE_ID';

const item = $input.item.json;
const results = item._results || [];
const platforms = Array.isArray(item.platforms) ? item.platforms : [];

if (!platforms.includes('facebook')) {
  return { json: { ...item, _results: [...results, { platform: 'facebook', skipped: true }] } };
}

let vault = item.source_vault || {};
if (typeof vault === 'string') try { vault = JSON.parse(vault); } catch { vault = {}; }
const files = vault.rawFiles || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master) {
  return { json: { ...item, _results: [...results, { platform: 'facebook', success: false, error: 'No content file' }] } };
}

function driveUrl(url) {
  if (!url || url.startsWith('/')) return null;
  if (url.includes('drive.google.com')) {
    const m = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
    if (m) return 'https://drive.google.com/uc?export=download&id=' + m[1];
  }
  return url;
}

const fileUrl = driveUrl(master.url);
if (!fileUrl) {
  return { json: { ...item, _results: [...results, { platform: 'facebook', success: false, error: 'File URL not public' }] } };
}

try {
  const ct = item.content_type || 'image';
  let res;
  if (ct === 'video' || ct === 'reel') {
    res = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${FB_PAGE}/videos`,
      qs: { file_url: fileUrl, description: item.caption || '', access_token: FB_TOKEN },
    });
  } else {
    res = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${FB_PAGE}/photos`,
      qs: { url: fileUrl, message: item.caption || '', access_token: FB_TOKEN },
    });
  }
  return { json: { ...item, _results: [...results, { platform: 'facebook', success: true, id: res.id || res.post_id }] } };
} catch (err) {
  return { json: { ...item, _results: [...results, { platform: 'facebook', success: false, error: err.message }] } };
}

// ═══ INSTAGRAM PUBLISHER ═══
// Handles single image, video/reel, and carousel posts.
// Uses container -> poll -> publish pattern.
//
// Setup: Same Meta App as Facebook.
//   1. Add Instagram Graph API product
//   2. Connect IG Business Account to FB Page
//   3. Get IG Business Account ID

const IG_TOKEN = 'YOUR_META_PAGE_ACCESS_TOKEN';
const IG_USER  = 'YOUR_INSTAGRAM_BUSINESS_ACCOUNT_ID';

const _http = this.helpers.httpRequest.bind(this.helpers);
const item = $input.item.json;
const results = item._results || [];
const platforms = Array.isArray(item.platforms) ? item.platforms : [];

if (!platforms.includes('instagram')) {
  return { json: { ...item, _results: [...results, { platform: 'instagram', skipped: true }] } };
}

let vault = item.source_vault || {};
if (typeof vault === 'string') try { vault = JSON.parse(vault); } catch { vault = {}; }
const files = vault.rawFiles || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master) {
  return { json: { ...item, _results: [...results, { platform: 'instagram', success: false, error: 'No content file' }] } };
}

function driveUrl(url) {
  if (!url || url.startsWith('/')) return null;
  if (url.includes('drive.google.com')) {
    const m = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
    if (m) return 'https://drive.google.com/uc?export=download&id=' + m[1];
  }
  return url;
}

async function waitForContainer(id) {
  for (let i = 0; i < 30; i++) {
    await new Promise(r => setTimeout(r, 5000));
    const s = await _http({ method: 'GET', url: `https://graph.facebook.com/v21.0/${id}`, qs: { fields: 'status_code', access_token: IG_TOKEN } });
    if (s.status_code === 'FINISHED') return;
    if (s.status_code === 'ERROR') throw new Error('Container failed: ' + JSON.stringify(s));
  }
  throw new Error('Container timed out after 150s');
}

const fileUrl = driveUrl(master.url);
if (!fileUrl) {
  return { json: { ...item, _results: [...results, { platform: 'instagram', success: false, error: 'File URL not public' }] } };
}

try {
  const ct = item.content_type || 'image';
  const caption = item.caption || '';
  let publishId;

  if (ct === 'carousel' && files.length > 1) {
    // Carousel: create child containers, then carousel container, then publish
    const childIds = [];
    for (const f of files) {
      const u = driveUrl(f.url);
      if (!u) continue;
      const c = await _http({ method: 'POST', url: `https://graph.facebook.com/v21.0/${IG_USER}/media`, qs: { image_url: u, is_carousel_item: true, access_token: IG_TOKEN } });
      childIds.push(c.id);
    }
    const container = await _http({ method: 'POST', url: `https://graph.facebook.com/v21.0/${IG_USER}/media`, qs: { media_type: 'CAROUSEL', children: childIds.join(','), caption, access_token: IG_TOKEN } });
    await waitForContainer(container.id);
    const pub = await _http({ method: 'POST', url: `https://graph.facebook.com/v21.0/${IG_USER}/media_publish`, qs: { creation_id: container.id, access_token: IG_TOKEN } });
    publishId = pub.id;
  } else if (ct === 'video' || ct === 'reel') {
    // Video/Reel: create REELS container, poll, publish
    const container = await _http({ method: 'POST', url: `https://graph.facebook.com/v21.0/${IG_USER}/media`, qs: { media_type: 'REELS', video_url: fileUrl, caption, access_token: IG_TOKEN } });
    await waitForContainer(container.id);
    const pub = await _http({ method: 'POST', url: `https://graph.facebook.com/v21.0/${IG_USER}/media_publish`, qs: { creation_id: container.id, access_token: IG_TOKEN } });
    publishId = pub.id;
  } else {
    // Single image: create container, poll, publish
    const container = await _http({ method: 'POST', url: `https://graph.facebook.com/v21.0/${IG_USER}/media`, qs: { image_url: fileUrl, caption, access_token: IG_TOKEN } });
    await waitForContainer(container.id);
    const pub = await _http({ method: 'POST', url: `https://graph.facebook.com/v21.0/${IG_USER}/media_publish`, qs: { creation_id: container.id, access_token: IG_TOKEN } });
    publishId = pub.id;
  }

  return { json: { ...item, _results: [...results, { platform: 'instagram', success: true, id: publishId }] } };
} catch (err) {
  return { json: { ...item, _results: [...results, { platform: 'instagram', success: false, error: err.message }] } };
}

// ═══ LINKEDIN PUBLISHER ═══
// Posts to LinkedIn Organization Page with image upload.
// Uses register upload -> binary upload -> UGC post pattern.
//
// Setup:
//   1. Create LinkedIn App at linkedin.com/developers
//   2. Request 'w_organization_social' scope
//   3. Generate OAuth2 access token
//   4. Get Organization ID from admin URL

const LI_TOKEN = 'YOUR_LINKEDIN_ACCESS_TOKEN';
const LI_ORG   = 'urn:li:organization:YOUR_ORG_ID';

const _http = this.helpers.httpRequest.bind(this.helpers);
const item = $input.item.json;
const results = item._results || [];
const platforms = Array.isArray(item.platforms) ? item.platforms : [];

if (!platforms.includes('linkedin')) {
  return { json: { ...item, _results: [...results, { platform: 'linkedin', skipped: true }] } };
}

let vault = item.source_vault || {};
if (typeof vault === 'string') try { vault = JSON.parse(vault); } catch { vault = {}; }
const files = vault.rawFiles || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master) {
  return { json: { ...item, _results: [...results, { platform: 'linkedin', success: false, error: 'No content file' }] } };
}

function driveUrl(url) {
  if (!url || url.startsWith('/')) return null;
  if (url.includes('drive.google.com')) {
    const m = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
    if (m) return 'https://drive.google.com/uc?export=download&id=' + m[1];
  }
  return url;
}

const fileUrl = driveUrl(master.url);
if (!fileUrl) {
  return { json: { ...item, _results: [...results, { platform: 'linkedin', success: false, error: 'File URL not public' }] } };
}

try {
  // Step 1: Register upload
  const reg = await _http({
    method: 'POST',
    url: 'https://api.linkedin.com/v2/assets?action=registerUpload',
    headers: { Authorization: 'Bearer ' + LI_TOKEN, 'Content-Type': 'application/json' },
    body: { registerUploadRequest: { recipes: ['urn:li:digitalmediaRecipe:feedshare-image'], owner: LI_ORG, serviceRelationships: [{ relationshipType: 'OWNER', identifier: 'urn:li:userGeneratedContent' }] } },
  });
  const uploadUrl = reg.value?.uploadMechanism?.['com.linkedin.digitalmedia.uploading.MediaUploadHttpRequest']?.uploadUrl;
  const asset = reg.value?.asset;
  if (!uploadUrl || !asset) throw new Error('Upload registration failed');

  // Step 2: Download from Drive, upload to LinkedIn
  const binary = await _http({ method: 'GET', url: fileUrl, encoding: 'arraybuffer' });
  await _http({ method: 'PUT', url: uploadUrl, headers: { Authorization: 'Bearer ' + LI_TOKEN }, body: binary });

  // Step 3: Create post
  const post = await _http({
    method: 'POST',
    url: 'https://api.linkedin.com/v2/ugcPosts',
    headers: { Authorization: 'Bearer ' + LI_TOKEN, 'Content-Type': 'application/json' },
    body: { author: LI_ORG, lifecycleState: 'PUBLISHED', specificContent: { 'com.linkedin.ugc.ShareContent': { shareCommentary: { text: item.caption || '' }, shareMediaCategory: 'IMAGE', media: [{ status: 'READY', media: asset }] } }, visibility: { 'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC' } },
  });

  return { json: { ...item, _results: [...results, { platform: 'linkedin', success: true, id: post.id }] } };
} catch (err) {
  return { json: { ...item, _results: [...results, { platform: 'linkedin', success: false, error: err.message }] } };
}

// Collect results from all platform nodes and build audit summary
const item = $input.item.json;
const results = item._results || [];
const published = results.filter(r => r.success);
const failed = results.filter(r => !r.success && !r.skipped);
const skipped = results.filter(r => r.skipped);

let summary;
if (published.length > 0 && failed.length === 0) {
  summary = 'Published to ' + published.map(r => r.platform).join(', ');
} else if (published.length > 0) {
  summary = 'Published to ' + published.map(r => r.platform).join(', ') + '. Failed: ' + failed.map(r => r.platform + ' (' + r.error + ')').join(', ');
} else if (failed.length > 0) {
  summary = 'All failed: ' + failed.map(r => r.platform + ' (' + r.error + ')').join(', ');
} else {
  summary = 'No active platforms (skipped: ' + skipped.map(r => r.platform).join(', ') + ')';
}

return { json: { postId: item.id, title: item.title, summary, publishedCount: published.length, failedCount: failed.length } };
